import { UnionFind } from 'union-find';

function solve(c, connections, queries) {
    // Initialize UnionFind structure to manage connected components
    const uf = new UnionFind(c + 1); // 1-based indexing
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    // Track online status: true means online, false means offline
    const online = new Array(c + 1).fill(true);
    // For each component, maintain a min-heap of online nodes
    const componentHeaps = new Map();

    // Initialize componentHeaps
    for (let i = 1; i <= c; i++) {
        const root = uf.find(i);
        if (!componentHeaps.has(root)) {
            componentHeaps.set(root, new MinHeap());
        }
        componentHeaps.get(root).insert(i);
    }

    const result = [];
    for (const [type, x] of queries) {
        if (type === 1) {
            const root = uf.find(x);
            const heap = componentHeaps.get(root);
            let minOnline = null;
            // Find the smallest online node in the component
            while (heap.size() > 0) {
                const current = heap.peek();
                if (online[current]) {
                    minOnline = current;
                    break;
                } else {
                    heap.extractMin();
                }
            }
            if (minOnline !== null) {
                if (minOnline === x && online[x]) {
                    result.push(x);
                } else {
                    result.push(minOnline);
                }
            } else {
                result.push(-1);
            }
        } else if (type === 2) {
            online[x] = false;
        }
    }
    return result;
}

// MinHeap implementation for JavaScript
class MinHeap {
    constructor() {
        this.heap = [];
    }

    insert(node) {
        this.heap.push(node);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.heap[parentIndex] > this.heap[index]) {
                [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    extractMin() {
        const min = this.heap[0];
        const last = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = last;
            this.sinkDown(0);
        }
        return min;
    }

    sinkDown(index) {
        const leftChild = 2 * index + 1;
        const rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this.heap[leftChild] < this.heap[smallest]) {
            smallest = leftChild;
        }
        if (rightChild < this.heap.length && this.heap[rightChild] < this.heap[smallest]) {
            smallest = rightChild;
        }
        if (smallest !== index) {
            [this.heap[smallest], this.heap[index]] = [this.heap[index], this.heap[smallest]];
            this.sinkDown(smallest);
        }
    }

    peek() {
        return this.heap[0];
    }

    size() {
        return this.heap.length;
    }
}

