import sys
import heapq
from collections import defaultdict

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    parent = [i for i in range(c + 1)]

    def find(u: int) -> int:
        while parent[u] != u:
            parent[u] = parent[parent[u]]
            u = parent[u]
        return u

    def union(u: int, v: int):
        root_u = find(u)
        root_v = find(v)
        if root_u != root_v:
            if root_u < root_v:
                parent[root_v] = root_u
            else:
                parent[root_u] = root_v

    for u, v in connections:
        union(u, v)

    online = [True] * (c + 1)
    component_heaps = defaultdict(list)

    for i in range(1, c + 1):
        root = find(i)
        heapq.heappush(component_heaps[root], i)

    result = []
    for query in queries:
        type_q, x = query
        if type_q == 1:
            root = find(x)
            heap = component_heaps[root]
            min_online = None
            while heap:
                current = heap[0]
                if online[current]:
                    min_online = current
                    break
                else:
                    heapq.heappop(heap)
            if min_online is not None:
                if min_online == x and online[x]:
                    result.append(x)
                else:
                    result.append(min_online)
            else:
                result.append(-1)
        elif type_q == 2:
            online[x] = False
    return result
